{
  "project_name": "奇幻选择之旅",
  "project_id": "b686df08-6655-4edb-a3a5-955f3244abe1",
  "one_liner": "一个让读者通过做选择来推进剧情的互动故事网页",
  "target_audience": "初中生（同龄人）",
  "skill_level": "零基础",
  "time_budget": "6小时",
  "tech_stack": "HTML + CSS + JavaScript（纯前端）",
  "problem_statement": "很多初中生喜欢看故事、玩游戏，但很少有适合零基础学生自己动手做的互动叙事作品。奇幻选择之旅让零基础学生也能从0开始，用最基础的网页技术做出一个属于自己的互动故事。",
  "success_criteria": [
    {
      "id": "sc_01",
      "description": "能顺畅展示一个完整故事，读者从开头读到结局，中间分支都能走通",
      "priority": "must"
    },
    {
      "id": "sc_02",
      "description": "至少有3个关键选择点，每个选择都有不同剧情走向",
      "priority": "must"
    },
    {
      "id": "sc_03",
      "description": "视觉风格统一好看，配色、字体、按钮整体协调",
      "priority": "nice_to_have"
    }
  ],
  "risks": [
    {
      "id": "risk_01",
      "description": "剧情卡壳写不出故事",
      "impact": "中",
      "fallback": "我提供故事模板和主线框架，学生直接套用填空"
    },
    {
      "id": "risk_02",
      "description": "零基础第一次写代码，进度慢",
      "impact": "高",
      "fallback": "我每一步都给出完整代码示例，引导学生逐行理解"
    },
    {
      "id": "risk_03",
      "description": "6小时内做不完完整功能",
      "impact": "中",
      "fallback": "按优先级砍功能：保留核心故事流程，砍掉动画效果和多结局"
    }
  ],
  "milestones": [
    {
      "id": "ms_01",
      "name": "故事创作",
      "estimated_hours": 1,
      "description": "确定故事主题、角色、3个选择点及分支结局"
    },
    {
      "id": "ms_02",
      "name": "页面骨架",
      "estimated_hours": 1.5,
      "description": "用HTML搭建故事展示页、选择按钮页、结局页的基础结构"
    },
    {
      "id": "ms_03",
      "name": "故事逻辑",
      "estimated_hours": 2,
      "description": "用JavaScript实现选择跳转、剧情推进、结局判定"
    },
    {
      "id": "ms_04",
      "name": "视觉美化",
      "estimated_hours": 1,
      "description": "加配色、字体、背景、按钮样式，让页面好看"
    },
    {
      "id": "ms_05",
      "name": "测试与展示",
      "estimated_hours": 0.5,
      "description": "完整走一遍故事流程，修复bug"
    }
  ],
  "created_at": "2026-06-30T13:20:00.000Z",
  "updated_at": "2026-06-30T13:33:00.000Z"
}

