      "story_data_schema": {
        "chapters": [
          {
            "id": "start",
            "title": "序章",
            "text": "故事正文...",
            "image": "scene_start",
            "options": [
              {"text": "选项A", "next": "chapter_a"},
              {"text": "选项B", "next": "chapter_b"}
            ]
          }
        ],
        "endings": [
          {
            "id": "ending_good",
            "title": "好结局",
            "text": "结局文本...",
